function importAllItemIDsCorrect() {
  const url = "https://raw.githubusercontent.com/ao-data/ao-bin-dumps/master/formatted/items.json";

  const response = UrlFetchApp.fetch(url);
  const data = JSON.parse(response.getContentText());

  const sheet = SpreadsheetApp.getActiveSpreadsheet().getActiveSheet();
  sheet.clear();

  const rows = [];
  rows.push(["UniqueName"]);

  for (let i = 0; i < data.length; i++) {
    if (data[i].UniqueName) {
      rows.push([data[i].UniqueName]);
    }
  }

  sheet.getRange(1, 1, rows.length, 1).setValues(rows);

  Logger.log("Imported rows: " + (rows.length - 1));
}

function importAlbionPricesEUClient() {
  const sheet = SpreadsheetApp.getActiveSpreadsheet().getActiveSheet();
  const lastRow = sheet.getLastRow();
  
  const euCities = ["Caerleon","Bridgewatch","Martlock","Lymhurst","Thetford","Fort Sterling"];
  sheet.getRange(1, 2, 1, euCities.length).setValues([euCities]);

  for (let i = 2; i <= lastRow; i++) {
    const itemID = sheet.getRange(i, 1).getValue();
    if (!itemID) continue;

    const url = `https://europe.albion-online-data.com/api/v2/stats/prices/${itemID}?locations=${euCities.join(",")}`;

    try {
      const response = UrlFetchApp.fetch(url);
      const data = JSON.parse(response.getContentText());

      const prices = euCities.map(city => {
        const cityData = data.find(d => d.city === city);
        return cityData ? cityData.sell_price_min : "N/A";
      });

      sheet.getRange(i, 2, 1, euCities.length).setValues([prices]);

    } catch (e) {
      const errorArr = Array(euCities.length).fill("Error");
      sheet.getRange(i, 2, 1, euCities.length).setValues([errorArr]);
    }
  }
}
